Bash(PGPASSWORD=postgres psql -h 127.0.0.1 -U postgres -d neuron_system -c "
CREATE TABLE IF NOT EXISTS nc_connector \(
    id varchar\(36\) NOT NULL,
    device_id varchar\(36\) NOT NULL,
    connector_id integer NOT NULL,
    status varchar\(20\) DEFAULT 'Available',
    current_power decimal\(10, 3\) DEFAULT NULL,
    current_energy decimal\(12, 3\) DEFAULT NULL,
    create_by varchar\(50\) DEFAULT NULL,
    create_time timestamp DEFAULT NULL,
    update_by varchar\(50\) DEFAULT NULL,
    update_time timestamp DEFAULT NULL,
    PRIMARY KEY \(id\)
\);
CREATE INDEX IF NOT EXISTS idx_connector_device_id ON nc_connector \(device_id\);
COMMENT ON TABLE nc_connector IS '充电枪/接口';
COMMENT ON COLUMN nc_connector.device_id IS '所属桩ID（关联nc_device）';
COMMENT ON COLUMN nc_connector.connector_id IS 'OCPP connectorId';
COMMENT ON COLUMN nc_connector.status IS '枪状态: Available/Charging/Faulted/Unavailable等';
COMMENT ON COLUMN nc_connector.current_power IS '当前充电功率\(kW\)';
COMMENT ON COLUMN nc_connector.current_energy IS '当前充电电量\(kWh\)';
")
